/**
 * Self-contained grading/ranking for the ingest Action — built from tv-fps
 * `src/grade.ts` (SMOOTHNESS_RUBRIC / gradeSmoothness / feelSortKey).
 * Regenerated by `node build.mjs`. Zero npm dependencies in-wall.
 *
 * DO NOT hand-edit the rubric thresholds — retune in tv-fps and rebuild.
 */

const LABELS = {
  premium: "Premium",
  smooth: "Smooth",
  ok: "OK",
  rough: "Rough",
  janky: "Janky",
};

const TIERS = ["premium", "smooth", "ok", "rough", "janky"];

/** THE rubric — keep in lockstep with tv-fps src/grade.ts SMOOTHNESS_RUBRIC. */
export const SMOOTHNESS_RUBRIC = {
  premium: { maxLocalPace: 0.15 },
  smooth: { maxHitchMs: 66, maxRate: 0.001 },
  ok: { maxHitchMs: 150, maxRate: 0.005 },
  rough: { maxHitchMs: 400, maxRate: 0.02 },
};

/** 0 (premium) … 4 (janky); 5 = ungraded (predates the smoothness metrics). */
export function smoothnessTierRank(r) {
  const hitches = r.hitches;
  if (hitches === undefined) return 5;
  const hitchMax = r.hitchMax ?? 0;
  const rate = r.frames !== undefined && r.frames > 0 ? hitches / r.frames : 0;
  const R = SMOOTHNESS_RUBRIC;
  if (hitches === 0 && (r.localPace ?? Infinity) < R.premium.maxLocalPace) return 0;
  if (hitchMax <= R.smooth.maxHitchMs && rate <= R.smooth.maxRate) return 1;
  if (hitchMax <= R.ok.maxHitchMs && rate <= R.ok.maxRate) return 2;
  if (hitchMax <= R.rough.maxHitchMs && rate <= R.rough.maxRate) return 3;
  return 4;
}

export function gradeSmoothness(r) {
  const rank = smoothnessTierRank(r);
  if (rank === 5) return null;
  const tier = TIERS[rank];
  return { tier, label: LABELS[tier] };
}

/**
 * Sort key for feel-ordered boards — mirrors worker BOARD_SORTS.feel drivers:
 * tier, hitch rate, hitchMax. Callers append fps DESC, p95 ASC.
 */
export function feelSortKey(r) {
  return {
    tier: smoothnessTierRank(r),
    rate: (r.hitches ?? 0) / Math.max(r.frames ?? 0, 1),
    hitchMax: r.hitchMax ?? 0,
  };
}

/** Comparator matching worker BOARD_SORTS.feel exactly. */
export function compareFeel(a, b) {
  const ka = feelSortKey(a);
  const kb = feelSortKey(b);
  if (ka.tier !== kb.tier) return ka.tier - kb.tier;
  if (ka.rate !== kb.rate) return ka.rate - kb.rate;
  if (ka.hitchMax !== kb.hitchMax) return ka.hitchMax - kb.hitchMax;
  if (a.fps !== b.fps) return b.fps - a.fps;
  if (a.p95 !== b.p95) return a.p95 - b.p95;
  return 0;
}
